const bounce = new THREE.DirectionalLight(0xffffff, 0.2);
bounce.position.set(0, -5, 3);
scene.add(bounce);

const EXTRUDE_H = 0.15;

const landMaterial = new THREE.MeshStandardMaterial({
  color: 0xf2f2f0,
  roughness: 0.72,
  metalness: 0,
});

const edgeMaterial = new THREE.LineBasicMaterial({
  color: 0x9a9a9a,
  linewidth: 1,
  transparent: true,
  opacity: 0.55,
});

function makeShape(points, depth) {
  const shape = new THREE.Shape();
  points.forEach(([x, y], index) => {
    if (index === 0) shape.moveTo(x, y);
    else shape.lineTo(x, y);
  });

  const geometry = new THREE.ExtrudeGeometry(shape, {
    depth,
    bevelEnabled: true,
    bevelSize: 0.012,
    bevelThickness: 0.012,
    bevelSegments: 3,
  });
  geometry.rotateX(-Math.PI / 2);
  geometry.computeVertexNormals();

  const mesh = new THREE.Mesh(geometry, landMaterial);
  mesh.castShadow = true;
  mesh.receiveShadow = true;
  mesh.add(
    new THREE.LineSegments(
      new THREE.EdgesGeometry(geometry, 30),
      edgeMaterial,
    ),
  );
  return mesh;
}

const mapGroup = new THREE.Group();
koreaShapes.forEach((points) => mapGroup.add(makeShape(points, EXTRUDE_H)));
mapGroup.position.y = -EXTRUDE_H / 2;
scene.add(mapGroup);

const ground = new THREE.Mesh(
  new THREE.PlaneGeometry(8, 8),
  new THREE.ShadowMaterial({ opacity: 0.3 }),
);
ground.rotation.x = -Math.PI / 2;
ground.position.y = -EXTRUDE_H / 2 - 0.001;
ground.receiveShadow = true;
scene.add(ground);

function geoToMap(lat, lon) {
  return new THREE.Vector3(
    -0.58 + ((lon - 126.1) / 3.5) * 1.2,
    EXTRUDE_H / 2,
    -(-0.6 + ((lat - 34.5) / 4.2) * 1.48),
  );
}

